1	export type Cell = [number, number];
2	
3	const NEIGHBORS_TO_SURVIVE = 2;
4	const NEIGHBORS_TO_BIRTH = 3;
5	
6	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
7	
8	const parseCellKey = (k: string): Cell => {
9	  const [xs, ys] = k.split(",");
10	  return [Number(xs), Number(ys)];
11	};
12	
13	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
14	  [-1, -1], [-1, 0], [-1, 1],
15	  [ 0, -1],          [ 0, 1],
16	  [ 1, -1], [ 1, 0], [ 1, 1],
17	];
18	
19	const countLiveNeighbors = (cells: Cell[]): Map<string, number> => {
20	  const counts = new Map<string, number>();
21	  for (const [x, y] of cells) {
22	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
23	      const k = cellKey([x + dx, y + dy]);
24	      counts.set(k, (counts.get(k) ?? 0) + 1);
25	    }
26	  }
27	  return counts;
28	};
29	
30	const survives = (neighborCount: number, isAlive: boolean): boolean =>
31	  neighborCount === NEIGHBORS_TO_BIRTH ||
32	  (neighborCount === NEIGHBORS_TO_SURVIVE && isAlive);
33	
34	export function nextGeneration(cells: Cell[]): Cell[] {
35	  const alive = new Set(cells.map(cellKey));
36	  const neighborCounts = countLiveNeighbors(cells);
37	
38	  const next: Cell[] = [];
39	  for (const [k, count] of neighborCounts) {
40	    if (survives(count, alive.has(k))) next.push(parseCellKey(k));
41	  }
42	  return next;
43	}
